const data = $input.first().json;
let appointmentStart;

if (data.preferredTime) {
  appointmentStart = parseNaturalTime(data.preferredTime);
} else {
  appointmentStart = getNextBusinessDay();
}

// Validate: if parsing failed or date is in the past
if (!appointmentStart || isNaN(appointmentStart.getTime()) || appointmentStart < new Date()) {
  appointmentStart = getNextBusinessDay();
}

function parseNaturalTime(input) {
  const text = input.toLowerCase().trim();
  const now = new Date();

  // WAT offset: work in UTC+1
  const watNow = new Date(now.getTime() + (1 * 60 * 60 * 1000));

  // Extract hour from phrases like "2pm", "2PM", "14:00", "2:30pm", "at 10"
  let hour = 10; // default to 10 AM if no time found
  let minute = 0;

  const timeMatch = text.match(/(\d{1,2})(?::(\d{2}))?\s*(am|pm)?/i);
  if (timeMatch) {
    hour = parseInt(timeMatch[1]);
    minute = timeMatch[2] ? parseInt(timeMatch[2]) : 0;
    const ampm = timeMatch[3];

    if (ampm) {
      if (ampm.toLowerCase() === 'pm' && hour < 12) hour += 12;
      if (ampm.toLowerCase() === 'am' && hour === 12) hour = 0;
    } else if (hour < 8) {
      // Ambiguous: "at 2" probably means 2 PM, not 2 AM
      hour += 12;
    }
  }

  // Handle "morning", "afternoon", "evening" if no specific time
  if (!timeMatch) {
    if (text.includes('morning')) hour = 10;
    else if (text.includes('afternoon')) hour = 14;
    else if (text.includes('evening')) hour = 17;
  }

  // Determine the date
  let targetDate = new Date(watNow);

  if (text.includes('today')) {
    // Keep today's date
  } else if (text.includes('tomorrow')) {
    targetDate.setDate(targetDate.getDate() + 1);
  } else if (text.includes('next week')) {
    targetDate.setDate(targetDate.getDate() + 7);
    // Move to Monday
    while (targetDate.getDay() !== 1) {
      targetDate.setDate(targetDate.getDate() + 1);
    }
  } else {
    // Check for day names: "monday", "tuesday", etc.
    const days = ['sunday','monday','tuesday','wednesday','thursday','friday','saturday'];
    const foundDay = days.findIndex(d => text.includes(d));

    if (foundDay !== -1) {
      const currentDay = watNow.getDay();
      let daysUntil = foundDay - currentDay;
      if (daysUntil <= 0) daysUntil += 7; // Always go forward
      targetDate.setDate(targetDate.getDate() + daysUntil);
    } else if (text.includes('in') && text.includes('hour')) {
      // "in 2 hours", "in an hour"
      const hoursMatch = text.match(/in\s+(\d+|an?)\s+hour/);
      if (hoursMatch) {
        const hrs = hoursMatch[1] === 'an' || hoursMatch[1] === 'a' ? 1 : parseInt(hoursMatch[1]);
        targetDate = new Date(watNow.getTime() + (hrs * 60 * 60 * 1000));
        // Use the computed time, not the extracted hour
        hour = targetDate.getUTCHours();
        minute = targetDate.getUTCMinutes();
      }
    } else {
      // Can't parse the date portion — default to tomorrow
      targetDate.setDate(targetDate.getDate() + 1);
    }
  }

  // Set the time (in UTC, so subtract 1 hour for WAT→UTC)
  targetDate.setUTCHours(hour - 1, minute, 0, 0);

  // Clamp to business hours: 9 AM - 5 PM WAT (8-16 UTC)
  const utcHour = targetDate.getUTCHours();
  if (utcHour < 8) targetDate.setUTCHours(8, 0, 0, 0);   // Before 9 AM WAT → 9 AM
  if (utcHour >= 16) targetDate.setUTCHours(8, 0, 0, 0);  // After 5 PM WAT → next day 9 AM
  if (utcHour >= 16) targetDate.setDate(targetDate.getDate() + 1);

  // Skip weekends
  while (targetDate.getDay() === 0 || targetDate.getDay() === 6) {
    targetDate.setDate(targetDate.getDate() + 1);
  }

  return targetDate;
}

function getNextBusinessDay() {
  const now = new Date();
  let next = new Date(now);
  next.setDate(next.getDate() + 1);

  while (next.getDay() === 0 || next.getDay() === 6) {
    next.setDate(next.getDate() + 1);
  }

  // 10:00 AM WAT = 09:00 UTC
  next.setUTCHours(9, 0, 0, 0);
  return next;
}

const appointmentEnd = new Date(appointmentStart);
appointmentEnd.setMinutes(appointmentEnd.getMinutes() + 30);

return [{
  json: {
    ...data,
    appointmentStart: appointmentStart.toISOString(),
    appointmentEnd: appointmentEnd.toISOString(),
    appointmentDisplay: appointmentStart.toLocaleString('en-NG', {
      weekday: 'long',
      year: 'numeric',
      month: 'long',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
      timeZone: 'Africa/Lagos'
    })
  }
}];
